export const checkId = 'cors';
export const name = 'CORS Configured';
export const appliesTo = ['deployable', 'server', 'framework'];

const CORS_PACKAGES = [
  'cors', '@fastify/cors', 'fastify-cors', 'koa-cors', 'koa2-cors',
  'micro-cors', 'nextjs-cors', '@elysiajs/cors', 'cors-anywhere',
  'itty-cors', 'express-cors', 'cors-express'
];

const SERVER_PACKAGES = [
  'express', 'fastify', 'koa', 'hono', 'restify', 'polka', 'hapi',
  '@hapi/hapi', 'connect', 'http-server', 'serve-static',
  'next', 'nuxt', 'astro', 'solid-start', 'remix', '@remix-run/serve',
  'nitro', 'nitropack', 'vercel', '@vercel/node', 'firebase-functions',
  '@netlify/functions', 'aws-lambda', 'serverless-http', 'json-server'
];

const RAW_SERVER_PACKAGES = [
  'express', 'fastify', 'koa', 'hono', 'restify', 'polka', 'hapi',
  '@hapi/hapi', 'connect', 'json-server'
];

const META_FRAMEWORKS = [
  'next', 'nuxt', 'astro', 'solid-start', 'remix', '@sveltejs/kit', 'gatsby'
];

const FRAMEWORK_SOURCE_NAMES = new Set([
  'express', 'fastify', 'koa', 'hono', 'next', 'nuxt', 'astro',
  'solid-start', 'remix', 'svelte', '@sveltejs/kit', 'vite', 'vitest',
  'webpack', 'rollup', 'esbuild', 'parcel', 'turbo', 'turborepo',
  'babel', 'swc', 'oxc', 'gulp', 'grunt', 'tsup', 'unbuild', 'lerna',
  'nx', 'bun', 'deno', 'pnpm', 'yarn', 'npm', 'changesets', 'biome',
  'prettier', 'eslint', 'typescript'
]);

const TOOL_KEYWORDS = new Set([
  'bundler', 'build-tool', 'compiler', 'transpiler', 'linter', 'formatter',
  'cli', 'command-line', 'scaffold', 'generator', 'test-runner', 'testing',
  'package-manager', 'monorepo', 'workspace', 'plugin', 'preset', 'toolkit'
]);

const TUTORIAL_PATTERN = /\b(learn|tutorial|example|examples|starter|template|boilerplate|course|guide|workshop|playground|docs|documentation|showcase|demo|sample|cheatsheet)\b/i;

const CORS_PATTERNS = [
  /require\s*\(\s*['"][^'"]*cors['"]\s*\)/,
  /import\s+.*?['"][^'"]*cors['"]/,
  /from\s+['"][^'"]*cors['"]/,
  /access-control-allow-origin/i,
  /access-control-allow-methods/i,
  /access-control-allow-headers/i,
  /access-control-allow-credentials/i,
  /access-control-expose-headers/i,
  /access-control-max-age/i,
  /access-control-request/i,
  /cors\s*:\s*(true|\{)/i,
  /cors\s*\(/i,
  /enableCors/i,
  /allowedOrigins?/i,
  /allowOrigin/i,
  /corsOrigins?/i,
  /use\s*\(\s*cors/i,
  /register\s*\([^)]*cors/i,
  /corsHandler/i,
  /handleCors/i,
  /withCors/i,
  /setHeader\s*\(\s*['"]Access-Control/i,
  /headers\s*\(\s*\)\s*\{[^}]*access-control/i,
];

function hasCorsDep(depsObj) {
  if (!depsObj) return null;
  const keys = Object.keys(depsObj);
  for (const pkg of CORS_PACKAGES) {
    if (keys.includes(pkg)) return pkg;
  }
  return null;
}

function hasServerDep(depsObj) {
  if (!depsObj) return false;
  const keys = Object.keys(depsObj);
  return keys.some(d => SERVER_PACKAGES.includes(d));
}

function hasRawServerDep(depsObj) {
  if (!depsObj) return false;
  const keys = Object.keys(depsObj);
  return keys.some(d => RAW_SERVER_PACKAGES.includes(d));
}

function hasMetaFrameworkDep(depsObj) {
  if (!depsObj) return false;
  const keys = Object.keys(depsObj);
  return keys.some(d => META_FRAMEWORKS.includes(d));
}

function basename(p) {
  const i = p.lastIndexOf('/');
  return i >= 0 ? p.slice(i + 1) : p;
}

function isTestOrExamplePath(p) {
  return /(^|\/)(test|tests|__tests__|spec|example|examples|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|node_modules|dist|build|coverage|\.tmp|\.next|out)\//i.test(p);
}

function isTutorialRepo(pj) {
  if (!pj) return false;
  const signals = [pj.name, pj.description, ...(pj.keywords || [])].filter(Boolean);
  return signals.some(s => TUTORIAL_PATTERN.test(s));
}

function isLibraryOrTool(pj, tree) {
  if (!pj) return false;
  const name = pj.name || '';
  const keywords = (pj.keywords || []).map(k => k.toLowerCase());
  const scripts = pj.scripts || {};
  const deps = { ...(pj.dependencies || {}), ...(pj.devDependencies || {}) };
  const baseName = name.replace(/^@[^/]+\//, '');

  if (pj.bin) return true;
  if (FRAMEWORK_SOURCE_NAMES.has(baseName) || FRAMEWORK_SOURCE_NAMES.has(name)) return true;

  if (pj.peerDependencies && Object.keys(pj.peerDependencies).length > 0) {
    if (!scripts.start && !scripts.serve && !scripts['start:prod'] && !hasRawServerDep(deps)) {
      return true;
    }
  }

  if (keywords.some(k => TOOL_KEYWORDS.has(k))) {
    if (!scripts.start && !scripts.serve && !hasRawServerDep(deps)) return true;
  }

  const isPrivate = pj.private === true;
  const hasWorkspaces = !!(pj.workspaces || tree.some(p => /^(pnpm-workspace\.yaml|turbo\.json|lerna\.json|nx\.json)$/.test(basename(p))));
  const hasPackagesDir = tree.some(p => /^packages\/[^/]+\//.test(p));
  const hasAppsDir = tree.some(p => /^(apps|services|sites)\/[^/]+\//.test(p));

  if (isPrivate && hasWorkspaces && hasPackagesDir && !hasAppsDir && !scripts.start && !scripts.serve) {
    return true;
  }

  if ((pj.main || pj.module || pj.exports || pj.types || pj.typings) && !scripts.start && !scripts.serve && !hasRawServerDep(deps)) {
    const devScript = scripts.dev || '';
    if (!/\b(next dev|nuxt dev|astro dev|remix dev|vite.*serve|serve)\b/.test(devScript)) {
      return true;
    }
  }

  return false;
}

function hasBackendContext(tree) {
  const apiRx = /\/(api|pages\/api|app\/api|server\/api|src\/app\/api|src\/pages\/api|src\/routes|routes|server\/routes|controllers|handlers|middleware|plugins)\/[^/]+\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/;
  const entryRx = /^(server|app|listen|main|worker)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/;
  const srcEntryRx = /^src\/(server|app|listen|main|worker)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/;

  for (const p of tree) {
    if (isTestOrExamplePath(p)) continue;
    if (apiRx.test(p) || entryRx.test(basename(p)) || srcEntryRx.test(p)) return true;
  }
  return false;
}

function isStaticOrSsrOnly(pj, tree) {
  const hasFrontend = tree.some(p => /\.(jsx|tsx|vue|svelte|html|css|scss|astro)$/.test(p));
  if (!hasFrontend) return false;
  if (hasBackendContext(tree)) return false;

  const deps = { ...(pj?.dependencies || {}), ...(pj?.devDependencies || {}) };
  const scripts = pj?.scripts || {};

  if (hasMetaFrameworkDep(deps)) return true;
  if (!hasServerDep(deps) && !scripts.start && !scripts.serve && !scripts['start:prod']) return true;

  return false;
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    if (repoType === 'empty' || tree.length === 0) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repo — CORS not applicable', findings: [] };
    }

    if (isTutorialRepo(packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Tutorial or example repo — CORS not applicable', findings: [] };
    }

    if (isLibraryOrTool(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library, tool, or framework source — CORS not applicable', findings: [] };
    }

    if (isStaticOrSsrOnly(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Static or SSR-only site with no API endpoints — CORS not applicable', findings: [] };
    }

    const rootDeps = { ...(packageJson?.dependencies || {}), ...(packageJson?.devDependencies || {}), ...(packageJson?.peerDependencies || {}) };
    const rootCors = hasCorsDep(rootDeps);
    if (rootCors) {
      return { checkId, status: 'pass', confidence: 'high', message: `CORS dependency found (${rootCors})`, findings: [] };
    }

    const isMonorepo = !!(packageJson?.workspaces || tree.some(p => /^(pnpm-workspace\.yaml|turbo\.json|lerna\.json|nx\.json)$/.test(basename(p))));
    if (isMonorepo) {
      const subPkgPaths = tree
        .filter(p => /(^|\/)package\.json$/.test(p) && !/node_modules/.test(p) && p !== 'package.json')
        .slice(0, 30);

      for (const pkgPath of subPkgPaths) {
        const content = await files.get(pkgPath);
        if (!content) continue;
        try {
          const subPkg = JSON.parse(content);
          const subDeps = { ...(subPkg.dependencies || {}), ...(subPkg.devDependencies || {}) };
          const subCors = hasCorsDep(subDeps);
          if (subCors) {
            return { checkId, status: 'pass', confidence: 'high', message: `CORS dependency found in ${pkgPath} (${subCors})`, findings: [{ file: pkgPath, issue: 'CORS dependency detected' }] };
          }
        } catch {
          // skip invalid JSON
        }
      }
    }

    const candidates = [];
    for (const p of tree) {
      if (!/\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) continue;
      if (isTestOrExamplePath(p)) continue;

      let score = 0;
      const b = basename(p);

      if (/\.config\.(js|ts|mjs|cjs)$/.test(b)) score += 100;
      if (/^(next|nuxt|astro|remix|svelte|vite|nitro)\.config\./.test(b)) score += 90;
      if (/^(server|app|listen|main|worker)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(b)) score += 80;
      if (/^src\/(server|app|listen|main|worker)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) score += 75;
      if (/\/(api|pages\/api|app\/api|server\/api|src\/app\/api|src\/pages\/api|routes|server\/routes|controllers|handlers|middleware|plugins)\/[^/]+\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) score += 70;
      if (/\.route\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) score += 50;
      if (/^(index|app)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(b)) score += 40;
      if (/^src\/(index|app)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) score += 35;

      if (score > 0) candidates.push({ path: p, score });
    }

    candidates.sort((a, b) => b.score - a.score);
    const scanPaths = candidates.slice(0, 25);

    for (const { path: filePath } of scanPaths) {
      const content = await files.get(filePath);
      if (!content) continue;

      for (const pattern of CORS_PATTERNS) {
        if (pattern.test(content)) {
